"Risk Variable All Encounter Diagnoses with POA Indication" AS (
SELECT * FROM "Encounter with Creatinine and without Obstetrical Conditions" AS QualifyingEncounter WHERE EXISTS (SELECT 1 FROM "Claim" AS claim WHERE fhirpath_text(claim.resource, 'status') = 'active' AND fhirpath_text(claim.resource, 'use') = 'claim' AND fhirpath_text(QualifyingEncounter.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(claim.resource, 'item.encounter.reference'), '/'), -1) AND EXISTS (SELECT 1 FROM (SELECT unnest(from_json(fhirpath(claim.resource, 'diagnosis'), '["VARCHAR"]')) AS _lt_D) AS _lt_unnest WHERE list_contains(from_json(fhirpath(claim.resource, 'item.diagnosisSequence'), '["VARCHAR"]'), fhirpath_text(_lt_D, 'sequence')) AND in_valueset(_lt_D, 'onAdmission', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1147.197')) AND claim.patient_id = QualifyingEncounter.patient_id)
