"Encounter with Kidney Dialysis Started 48 Hours or Less After Arrival without High Creatinine" AS (
SELECT * FROM "Encounter with Kidney Dialysis Started 48 Hours or Less After Arrival" AS EncounterWithKidneyDialysis48HoursOrAfter WHERE NOT EXISTS (SELECT * FROM "Encounter with 2 Times Serum Creatinine Increase" AS EncounterWithHighCreatinine WHERE intervalIncludes(fhirpath_text(EncounterWithHighCreatinine.resource, 'period'), fhirpath_text(EncounterWithKidneyDialysis48HoursOrAfter.resource, 'period')) AND EncounterWithHighCreatinine.patient_id = EncounterWithKidneyDialysis48HoursOrAfter.patient_id)
),
"Denominator Exclusion" AS (
(SELECT patient_id, resource FROM "Encounter with Less Than 2 Creatinine Results within 48 Hours of Arrival") UNION (SELECT patient_id, resource FROM "Encounter with Index eGFR Less Than 60 within First 48 Hours") UNION (SELECT patient_id, resource FROM "Encounter with 0.3 mg dL or More Increase in Creatinine") UNION (SELECT patient_id, resource FROM "Encounter with Kidney Dialysis Started 48 Hours or Less After Arrival without High Creatinine") UNION (SELECT patient_id, resource FROM "Encounter with High Risk Diagnosis for AKI") UNION (SELECT patient_id, resource FROM "Encounter with High Risk Procedures for AKI")
),
"Encounter with Kidney Dialysis Started More Than 48 Hours After Arrival without High Creatinine" AS (
SELECT * FROM "Encounter with Kidney Dialysis Started More Than 48 Hours After Arrival" AS EncounterWithDialysisAfter48Hours WHERE NOT EXISTS (SELECT * FROM "Encounter with 2 Times Serum Creatinine Increase" AS EncounterWithHighCreatinine WHERE intervalIncludes(fhirpath_text(EncounterWithHighCreatinine.resource, 'period'), fhirpath_text(EncounterWithDialysisAfter48Hours.resource, 'period')) AND EncounterWithHighCreatinine.patient_id = EncounterWithDialysisAfter48Hours.patient_id)
),
"Numerator" AS (
(SELECT patient_id, resource FROM "Encounter with 2 Times Serum Creatinine Increase") UNION (SELECT patient_id, resource FROM "Encounter with Kidney Dialysis Started More Than 48 Hours After Arrival without High Creatinine")
)
SELECT p.patient_id, (SELECT COALESCE(LIST("Initial Population".resource), []) FROM "Initial Population" WHERE "Initial Population".patient_id = p.patient_id AND "Initial Population".resource IS NOT NULL) AS "Initial Population", (SELECT COALESCE(LIST("Denominator".resource), []) FROM "Denominator" WHERE "Denominator".patient_id = p.patient_id AND "Denominator".resource IS NOT NULL) AS Denominator, (SELECT COALESCE(LIST("Denominator Exclusion".resource), []) FROM "Denominator Exclusion" WHERE "Denominator Exclusion".patient_id = p.patient_id AND "Denominator Exclusion".resource IS NOT NULL) AS "Denominator Exclusion", (SELECT COALESCE(LIST("Numerator".resource), []) FROM "Numerator" WHERE "Numerator".patient_id = p.patient_id AND "Numerator".resource IS NOT NULL) AS Numerator FROM _patients p ORDER BY p.patient_id ASC
